     1→import { assertEquals, assertMatch, assertStringIncludes } from "@std/assert";
     2→import { convert } from "./mod.ts";
     3→
     4→const ARTICLE_HTML = `
     5→<html>
     6→  <head>
     7→    <title>My Test Article</title>
     8→    <meta name="description" content="A short description.">
     9→    <meta property="og:title" content="OG Title Override">
    10→  </head>
    11→  <body>
    12→    <nav>Skip this nav</nav>
    13→    <header>Skip this header</header>
    14→    <article>
    15→      <h1>Main Heading</h1>
    16→      <p>This is <strong>bold</strong> and <em>italic</em> text.</p>
    17→      <pre><code class="language-ts">const x: number = 1;</code></pre>
    18→      <table>
    19→        <tr><th>Name</th><th>Value</th></tr>
    20→        <tr><td>foo</td><td>bar</td></tr>
    21→      </table>
    22→      <img src="photo.jpg" alt="A photo">
    23→      <p>Visit <a href="https://example.com">example.com</a> for more.</p>
    24→      <del>deleted text</del>
    25→    </article>
    26→    <footer>Skip this footer</footer>
    27→  </body>
    28→</html>
    29→`;
    30→
    31→Deno.test("frontmatter: includes title and date by default", () => {
    32→  const { markdown } = convert(ARTICLE_HTML, {
    33→    url: "https://example.com/page",
    34→  });
    35→  assertStringIncludes(markdown, "---");
    36→  assertStringIncludes(markdown, 'url: "https://example.com/page"');
    37→  assertMatch(markdown, /date: \d{4}-\d{2}-\d{2}/);
    38→});
    39→
    40→Deno.test("frontmatter: og:title takes precedence over <title>", () => {
    41→  const { markdown } = convert(ARTICLE_HTML);
    42→  assertStringIncludes(markdown, 'title: "OG Title Override"');
    43→});
    44→
    45→Deno.test("frontmatter: description from meta tag", () => {
    46→  const { markdown } = convert(ARTICLE_HTML);
    47→  assertStringIncludes(markdown, "A short description.");
    48→});
    49→
    50→Deno.test("frontmatter: omitted with no-frontmatter option", () => {
    51→  const { markdown } = convert(ARTICLE_HTML, { frontmatter: false });
    52→  assertEquals(markdown.startsWith("---"), false);
    53→});
    54→
    55→Deno.test("reader mode: strips nav, header, footer", () => {
    56→  const { markdown } = convert(ARTICLE_HTML, { frontmatter: false });
    57→  assertEquals(markdown.includes("Skip this nav"), false);
    58→  assertEquals(markdown.includes("Skip this header"), false);
    59→  assertEquals(markdown.includes("Skip this footer"), false);
    60→});
    61→
    62→Deno.test("reader mode: keeps article content", () => {
    63→  const { markdown } = convert(ARTICLE_HTML, { frontmatter: false });
    64→  assertStringIncludes(markdown, "Main Heading");
    65→  assertStringIncludes(markdown, "bold");
    66→});
    67→
    68→Deno.test("code blocks: preserved as fenced blocks", () => {
    69→  const { markdown } = convert(ARTICLE_HTML, { frontmatter: false });
    70→  assertStringIncludes(markdown, "```");
    71→  assertStringIncludes(markdown, "const x");
    72→});
    73→
    74→Deno.test("tables: converted to markdown tables", () => {
    75→  const { markdown } = convert(ARTICLE_HTML, { frontmatter: false });
    76→  assertStringIncludes(markdown, "Name");
    77→  assertStringIncludes(markdown, "foo");
    78→});
    79→
    80→Deno.test("images: kept by default", () => {
    81→  // Reader mode may strip figures, but --full should keep images
    82→  const { markdown } = convert(ARTICLE_HTML, {
    83→    frontmatter: false,
    84→    reader: false,
    85→  });
    86→  assertStringIncludes(markdown, "photo.jpg");
    87→});
    88→
    89→Deno.test("stripImages: removes images when flag set", () => {
    90→  const { markdown } = convert(ARTICLE_HTML, {
    91→    frontmatter: false,
    92→    reader: false,
    93→    stripImages: true,
    94→  });
    95→  assertEquals(markdown.includes("photo.jpg"), false);
    96→});
    97→
    98→Deno.test("stripLinks: converts links to plain text", () => {
    99→  const { markdown } = convert(ARTICLE_HTML, {
   100→    frontmatter: false,
   101→    stripLinks: true,
   102→  });
   103→  assertEquals(markdown.includes("https://example.com"), false);
   104→  assertStringIncludes(markdown, "example.com");
   105→});
   106→
   107→Deno.test("strikethrough: rendered as ~~text~~", () => {
   108→  const { markdown } = convert(ARTICLE_HTML, { frontmatter: false });
   109→  assertStringIncludes(markdown, "~~deleted text~~");
   110→});
   111→
   112→Deno.test("full mode: keeps body content without reader extraction", () => {
   113→  const { markdown } = convert(ARTICLE_HTML, {
   114→    frontmatter: false,
   115→    reader: false,
   116→  });
   117→  assertStringIncludes(markdown, "Main Heading");
   118→});
   119→
   120→Deno.test("convert: returns title and description in result", () => {
   121→  const result = convert(ARTICLE_HTML);
