     1→#!/usr/bin/env -S deno run --allow-read --allow-env
     2→
     3→import { parseArgs } from "@std/cli/parse-args";
     4→import { convert } from "./mod.ts";
     5→
     6→const HELP = `
     7→html2md — convert HTML to Markdown for LLM context
     8→
     9→USAGE
    10→  curl -s <url> | html2md [options]
    11→  cat page.html  | html2md [options]
    12→
    13→OPTIONS
    14→  --url <url>         Source URL (adds to frontmatter, used for context)
    15→  --full              Convert entire page instead of reader-mode extraction
    16→  --no-frontmatter    Omit YAML frontmatter
    17→  --strip-images      Remove images
    18→  --strip-links       Convert links to plain text
    19→  -h, --help          Show this help
    20→
    21→EXAMPLES
    22→  curl -s https://example.com | html2md
    23→  curl -s https://docs.deno.com/runtime/ | html2md --url https://docs.deno.com/runtime/
    24→  curl -s https://example.com | html2md --full --no-frontmatter
    25→  curl -s https://example.com | html2md --strip-links > context.md
    26→`.trim();
    27→
    28→if (import.meta.main) {
    29→  const flags = parseArgs(Deno.args, {
    30→    boolean: ["full", "frontmatter", "strip-images", "strip-links", "help"],
    31→    string: ["url"],
    32→    alias: { h: "help" },
    33→    default: { frontmatter: true },
    34→    negatable: ["frontmatter"],
    35→  });
    36→
    37→  if (flags.help) {
    38→    console.log(HELP);
    39→    Deno.exit(0);
    40→  }
    41→
    42→  const chunks: Uint8Array[] = [];
    43→  for await (const chunk of Deno.stdin.readable) {
    44→    chunks.push(chunk);
    45→  }
    46→
    47→  const totalLength = chunks.reduce((sum, c) => sum + c.length, 0);
    48→  const merged = new Uint8Array(totalLength);
    49→  let offset = 0;
    50→  for (const chunk of chunks) {
    51→    merged.set(chunk, offset);
    52→    offset += chunk.length;
    53→  }
    54→
    55→  const html = new TextDecoder().decode(merged);
    56→
    57→  if (!html.trim()) {
    58→    console.error("html2md: no input received on stdin");
    59→    Deno.exit(1);
    60→  }
    61→
    62→  const { markdown } = convert(html, {
    63→    reader: !flags.full,
    64→    frontmatter: flags.frontmatter,
    65→    url: flags.url,
    66→    stripImages: flags["strip-images"],
    67→    stripLinks: flags["strip-links"],
    68→  });
    69→
    70→  console.log(markdown);
    71→}
    72→

