     1→export function buildFrontmatter(
     2→  title: string,
     3→  description: string,
     4→  url?: string,
     5→): string {
     6→  const date = new Date().toISOString().split("T")[0];
     7→  const lines = ["---"];
     8→  if (title) lines.push(`title: "${title.replace(/"/g, '\\"')}"`);
     9→  if (url) lines.push(`url: "${url}"`);
    10→  lines.push(`date: ${date}`);
    11→  if (description) {
    12→    lines.push(`description: "${description.replace(/"/g, '\\"')}"`);
    13→  }
    14→  lines.push("---");
    15→  return lines.join("\n");
    16→}
