     3→export interface MarkdownOptions {
     4→  stripImages?: boolean;
     5→  stripLinks?: boolean;
     6→}
     7→
     8→export function buildTurndown(opts: MarkdownOptions): TurndownService {
     9→  // deno-lint-ignore no-explicit-any
    10→  const td = new (TurndownService as any)({
    11→    headingStyle: "atx",
    12→    codeBlockStyle: "fenced",
    13→    bulletListMarker: "-",
    14→    hr: "---",
    15→    linkStyle: "inlined",
    16→  });
    17→
    18→  td.remove(["script", "style", "noscript", "iframe"]);
    19→
    20→  if (opts.stripImages) {
    21→    td.addRule("stripImages", {
    22→      filter: ["img", "picture", "figure"],
    23→      replacement: () => "",
    24→    });
    25→  }
    26→
    27→  if (opts.stripLinks) {
    28→    td.addRule("plainLinks", {
    29→      filter: "a",
    30→      replacement: (content: string) => content,
    31→    });
    32→  }
    33→
    34→  td.addRule("strikethrough", {
    35→    filter: ["del", "s", "strike"],
    36→    replacement: (content: string) => `~~${content}~~`,
    37→  });
    38→
    39→  return td;
    40→}
